import{_ as a,c as t,o,ak as s,al as i}from"./chunks/framework.BqsDZCpP.js";const f=JSON.parse('{"title":"AireFlow Release Notes","description":"","frontmatter":{},"headers":[],"relativePath":"aireblock-releases/aireflow-v2-38-0.md","filePath":"aireblock-releases/aireflow-v2-38-0.md","lastUpdated":1775826521000}'),r={name:"aireblock-releases/aireflow-v2-38-0.md"};function n(l,e,d,c,h,m){return o(),t("div",null,[...e[0]||(e[0]=[s('<h1 id="aireflow-release-notes" tabindex="-1"><span class="fsc-product"><img src="'+i+'"> AireFlow Release Notes</span> <a class="header-anchor" href="#aireflow-release-notes" aria-label="Permalink to “AireFlow Release Notes”">​</a></h1><blockquote><p><strong>Version:</strong> 2.38.0<br><strong>Release Date:</strong> 21st April 2026</p></blockquote><h2 id="summary-of-changes" tabindex="-1">Summary of Changes <a class="header-anchor" href="#summary-of-changes" aria-label="Permalink to “Summary of Changes”">​</a></h2><h4 id="✨-new-features" tabindex="-1">✨ New Features <a class="header-anchor" href="#✨-new-features" aria-label="Permalink to “✨ New Features”">​</a></h4><ul><li>Transition Sets - FLOW-1229</li><li>Pass Form Context to Form Tasks - FLOW-1269</li></ul><h4 id="⚡-improvements" tabindex="-1">⚡ Improvements <a class="header-anchor" href="#⚡-improvements" aria-label="Permalink to “⚡ Improvements”">​</a></h4><ul><li>Improved Workflow Builder UI - FLOW-1283 / FLOW-1284</li></ul><hr><h1 id="detailed-changes" tabindex="-1">Detailed Changes <a class="header-anchor" href="#detailed-changes" aria-label="Permalink to “Detailed Changes”">​</a></h1><h3 id="✨-new-features-1" tabindex="-1">✨ New Features <a class="header-anchor" href="#✨-new-features-1" aria-label="Permalink to “✨ New Features”">​</a></h3><hr><h4 id="transition-sets-flow-1229" tabindex="-1">Transition Sets (FLOW-1229) <a class="header-anchor" href="#transition-sets-flow-1229" aria-label="Permalink to “Transition Sets (FLOW-1229)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>Transition Sets are a powerful new feature that allows configurators to define and control exactly which status transitions are permitted for tasks within a workflow. Each set defines a named collection of allowed transitions with customisable labels, and can be assigned to individual task definitions. A default transition set is provided for backwards compatibility, ensuring existing workflows continue to behave as expected. Transition sets can be created and managed directly in the UI, imported from git repositories, duplicated, and viewed as a diagram. Permission policies can also be applied to control which users are permitted to make each transition.</p></div><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>You now have fine-grained control over how tasks move through statuses in your workflows. Rather than every task having the same fixed set of transitions available, you can create custom transition sets — for example, restricting certain statuses so that only automated processes or specific roles can trigger them. This makes it easier to enforce business rules, reduce errors, and build more sophisticated, governed workflows.</p></div><h4 id="pass-form-context-to-form-tasks-flow-1269" tabindex="-1">Pass Form Context to Form Tasks (FLOW-1269) <a class="header-anchor" href="#pass-form-context-to-form-tasks-flow-1269" aria-label="Permalink to “Pass Form Context to Form Tasks (FLOW-1269)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>It is now possible to specify context values when creating a form instance via a Form task. These values are passed to AireForms as instance context and become available within the form via XPath, allowing data from a previous form submission that triggered the workflow to be forwarded into a newly created form.</p></div><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>You can now configure a form task to pass values into the form it creates. This means users filling in forms created by tasks will have relevant information pre-populated or available in context, reducing duplication and making multi-step form workflows much smoother.</p></div><h3 id="⚡-improvements-1" tabindex="-1">⚡ Improvements <a class="header-anchor" href="#⚡-improvements-1" aria-label="Permalink to “⚡ Improvements”">​</a></h3><hr><h4 id="improved-workflow-builder-ui-flow-1283-flow-1284" tabindex="-1">Improved Workflow Builder UI (FLOW-1283 / FLOW-1284) <a class="header-anchor" href="#improved-workflow-builder-ui-flow-1283-flow-1284" aria-label="Permalink to “Improved Workflow Builder UI (FLOW-1283 / FLOW-1284)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>Several enhancements have been made to the workflow and task editor UI. Boolean fields that previously displayed as true/false dropdowns have been replaced with toggle switches throughout. Fields that accept a constrained list of values — such as http content-type — now support two input modes: a static mode presenting valid options as a dropdown, and a mapped mode for entering a Liquid or XPath expression.</p></div><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>The workflow builder is now more intuitive and easier to use. Binary settings are displayed as toggles rather than dropdowns, and fields with a fixed set of valid values now guide you to pick from a list rather than requiring you to type a value manually — with the option to switch to a dynamic expression when needed.</p></div>',22)])])}const u=a(r,[["render",n]]);export{f as __pageData,u as default};
